import { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { fetchGroups } from '../services/api';
import groupImage from '../assets/bretagne.jpg';
import '../styles/Groups.css'; // Import du fichier CSS

export default function Groups() {
    const [groups, setGroups] = useState([]);
    const navigate = useNavigate();

    useEffect(() => {
        fetchGroups().then(data => setGroups(data));
    }, []);

    return (
        <div className="groups-container">
            <h1 className="groups-title">Mes Groupes</h1>

            <div className="groups-grid">
            {groups.map(group => (
                <div
                    key={group.id}
                    onClick={() => navigate(`/groups/${group.id}`)}
                    className="rounded-xl overflow-hidden shadow-md cursor-pointer transition-transform transform hover:scale-105 bg-white"
                >
                    <div className="relative w-full h-40">
                        <img
                            src={group.image}
                            alt={group.name}
                            className="absolute inset-0 w-full h-full object-cover"
                        />
                    </div>
                    <div className="p-4">
                        <h2 className="font-semibold text-lg">{group.name}</h2>
                        <p className="text-sm text-gray-600">{group.members.length} membres</p>
                    </div>
                </div>
            ))}


            </div>
        </div>
    );
}
